define &quot;Numerator&quot;:
  ( exists ( &quot;Four DTaP Vaccinations&quot; )
      or exists ( &quot;DTaP Numerator Inclusion Conditions&quot; )
  )
    and ( exists ( &quot;Three Polio Vaccinations&quot; )
        or exists ( &quot;Polio Numerator Inclusion Conditions&quot; )
